awk -F'\t' '
$1 >= 10485760 && $2 !~ /\/var\/data$/ && $2 !~ /\/var\/data\/[^\/]+$/ && !($2 ~ /\/var\/data\/cache\/thumbnails$/) {
  mb = int($1 / 1048576)
  print mb, $1, $2
}' /home/user/disk_inventory.txt | sort -t' ' -k2,2nr -k3,3 | awk '{print $1"MB "$3}' > /home/user/reports/large_files.txt

awk -F'\t' '
BEGIN { OFS="," }
{
  path = $2
  bytes = $1
  # Skip directory entries (paths that are /var/data or /var/data/X or /var/data/X/Y where they are dirs)
  if (path == "/var/data") next
  if (path == "/var/data/logs") next
  if (path == "/var/data/backups") next
  if (path == "/var/data/cache") next
  if (path == "/var/data/cache/thumbnails") next
  if (path == "/var/data/uploads") next
  if (path == "/var/data/archives") next

  # Get filename from path
  n = split(path, parts, "/")
  filename = parts[n]

  # Get extension
  if (index(filename, ".") > 0) {
    n = split(filename, fparts, ".")
    ext = tolower(fparts[n])
  } else {
    ext = "NO_EXTENSION"
  }

  totals[ext] += bytes
}
END {
  print "extension,total_bytes"
  for (ext in totals) {
    print ext, totals[ext]
  }
}' /home/user/disk_inventory.txt | (read header; echo "$header"; sort -t',' -k2,2nr) > /home/user/reports/extension_summary.csv
